                        <h1> {{ Publicaciones.publicaciones_titulo }}</h1>
                    </div>

                    <h4>
                  <router-link to="/">INICIO</router-link>
                </h4>
                <h5>
                  <router-link to="/publicaciones">PUBLICACIONES</router-link>
                </h5>
                <h3>{{ Publicaciones.publicaciones_titulo }}</h3>
                </div>
            </div>
        </div>
    </div>

    <!-- ==============================================
    ** Blog Detail **
    =================================================== -->
    <div class="container blog-wrapper padding-lg">
        <div class="row">
            <!-- Start Left Column -->
            <div class="col-sm-8 blog-left">
                <ul class="blog-listing detail">
                    <li> 
                      <img
                    :src="
                      url_api +
                      '/Publicaciones/' +
                      Publicaciones.publicaciones_imagen
                    "
                    alt="img"
                    style="cursor: zoom-in"
                    class="img-responsive"
                  />
                 
                        <h2>{{ Publicaciones.publicaciones_titulo }}</h2>
                        <ul class="post-detail">
                            <li><span class="icon-date-icon ico"></span><span class="bold">{{ dmy(Publicaciones.publicaciones_fecha) }}</span> </li>
                            <li>Publicado Por: <span class="bold">{{ Publicaciones.publicaciones_autor }}</span></li>
                            <li><span class="label"><router-link to="/publicaciones">PUBLICACIONES</router-link></span></li>
                        </ul>
                        <p class=" left-aligned" v-html="Publicaciones.publicaciones_descripcion"></p>
